data.content:
Here's how to use MSTest's comparison assertions for your `ScoreCalculator`:

**Key assertions for boundary checking:**

| Assertion | Usage |
|-----------|-------|
| `Assert.IsInRange(actual, low, high)` | Value falls within bounds |
| `Assert.IsGreaterThan(lowerBound, actual)` | Value exceeds a threshold |
| `Assert.IsLessThan(upperBound, actual)` | Value is below a threshold |

**Example test class:**

```csharp
[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    [TestMethod]
    [DataRow(5, 10, 50.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_AnyValidInput_ReturnsInRange()
    {
        var result = _calculator.CalculatePercentage(7, 10);

        // Verify result is always between 0 and 100 inclusive
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_BelowMax_ReturnsGreaterThanZero()
    {
        var result = _calculator.NormalizeScore(25.0, 50.0);

        Assert.IsGreaterThan(0.0, result);
        Assert.IsLessThan(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var result = _calculator.NormalizeScore(120.0, 100.0);

        // Capped — should not exceed 100
        Assert.IsInRange(result, 0.0, 100.0);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.9, "C")]
    [DataRow(70.0, "C")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    public void GetGrade_AtBoundaries_ReturnsCorrectGrade(double percentage, string expected)
    {
        Assert.AreEqual(expected, _calculator.GetGrade(percentage));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }
}
```

**Summary of the comparison assertions used:**

- `Assert.IsInRange(result, 0.0, 100.0)` — verifies percentage stays within valid bounds
- `Assert.IsGreaterThan(0.0, result)` — confirms score exceeds zero
- `Assert.IsLessThan(100.0, result)` — confirms score is below the cap

These produce much clearer failure messages than `Assert.IsTrue(result > 0)` would. They require **MSTest 3.8+** (available via the `MSTest` metapackage or `MSTest.Sdk`).
